// Extract and format data from Airtable for CTA flow
const data = $input.first().json;

// Handle both nested (fields) and flat structure
const source = data.fields || data;

// Parse pdf_brief from cta_context
let pdfBrief = {};
try {
  // Try cta_context first (dedicated field - stringified pdf_brief)
  if (source.cta_context) {
    // Clean encoding issues - stray backslashes before underscores from Airtable
    let ctxString = source.cta_context.trim();
    ctxString = ctxString.replace(/\\_/g, '_');
    pdfBrief = JSON.parse(ctxString);
  }
  // Fallback: try parsing cta_data if it's a JSON string
  else if (source.cta_data && typeof source.cta_data === 'string' && source.cta_data !== 'true' && source.cta_data !== 'false') {
    const ctaParsed = JSON.parse(source.cta_data);
    pdfBrief = ctaParsed.pdf_brief || ctaParsed;
  }
} catch (e) {
  console.log('Could not parse PDF brief, using defaults');
  pdfBrief = {};
}

// Extract tweet content
const tweetContent = source.tweet_content || source['Tweet Content'];

// Build formatted research from pdf_brief
const formattedResearch = pdfBrief.sections 
  ? `**PDF Title:** ${pdfBrief.title || 'Lead Magnet'}\n**Subtitle:** ${pdfBrief.subtitle || 'A comprehensive guide'}\n**Sections:**\n${pdfBrief.sections.map((s, i) => `${i+1}. ${s}`).join('\n')}\n**Key Deliverables:**\n${(pdfBrief.key_deliverables || []).map(d => `- ${d}`).join('\n')}\n**Target Word Count:** ${pdfBrief.target_word_count || 1500}\n**Tone:** ${pdfBrief.tone || 'educational'}`
  : '**No PDF brief provided - generate based on tweet content**';

// Extract and prepare all data for downstream nodes
const output = {
  // Core identifiers
  airtable_id: data.id,

  // Tweet content and metadata
  tweet_content: tweetContent,
  cta_type: source.cta_type || source['CTA Type'] || 'engagement',
  strategy_type: source.generation_mode || source['Strategy Type'] || 'exploit',
  has_cta: true,
  hook_type: source.hook_type || source['Hook Type'] || 'value',
  viral_score: source.critique_score || source['Viral Score'] || 0,

  // PDF Brief (the new structured data)
  pdf_brief: pdfBrief,

  // Formatted for Generate HTML Content
  formatted_research: formattedResearch,

  // Timestamps
  created_at: source.created_at || source['Created At'],
  approved_at: new Date().toISOString()
};

// Validation
if (!output.tweet_content) {
  throw new Error('Tweet Content is missing from Airtable record');
}

console.log('✅ Data prepared for CTA flow:', {
  cta_type: output.cta_type,
  has_pdf_brief: !!pdfBrief.title,
  pdf_sections: pdfBrief.sections?.length || 0,
  content_length: output.tweet_content.length
});

return { json: output };

