// PROCESS CRITIQUE v5.1 - References Parse AI Generate Tweet for clean data
const input = $input.first().json;
const prefetch = $('Data Prefetch').first().json;

// Self-Critique output - handle Agent wrapping
const critiqueOutput = input.output || input;

// Initialize defaults
let scores = { scroll_stop: 7, human_voice: 7, freshness: 7 };
let avgScore = 7;
let fatigueViolations = [];
let issues = [];
let action = 'pass';
let tweet = '';

// Check if structured output (object) or text output (string)
if (typeof critiqueOutput === 'object' && critiqueOutput !== null) {
  if (critiqueOutput.scores) {
    scores = {
      scroll_stop: critiqueOutput.scores.scroll_stop || 7,
      human_voice: critiqueOutput.scores.human_voice || 7,
      freshness: critiqueOutput.scores.freshness || 7,
      strategy_fit: critiqueOutput.scores.strategy_fit || 7
    };
  }
  avgScore = critiqueOutput.average_score || Math.round((scores.scroll_stop + scores.human_voice + scores.freshness + scores.strategy_fit) / 4);
  fatigueViolations = Array.isArray(critiqueOutput.fatigue_violations) ? critiqueOutput.fatigue_violations : [];
  issues = Array.isArray(critiqueOutput.issues) ? critiqueOutput.issues : [];
  action = critiqueOutput.action || 'pass';
  tweet = critiqueOutput.final_tweet || '';
} else {
  const outputStr = String(critiqueOutput || '');
  const scoreMatch = outputStr.match(/SCORE:\s*(\d+)/i);
  avgScore = scoreMatch ? parseInt(scoreMatch[1]) : 7;
  const actionMatch = outputStr.match(/ACTION:\s*(pass|rewrite|reject)/i);
  action = actionMatch ? actionMatch[1].toLowerCase() : 'pass';
  const finalMatch = outputStr.match(/FINAL_TWEET:\s*([\s\S]*?)$/i);
  tweet = finalMatch ? finalMatch[1].trim() : '';
}

// Clean tweet line breaks
tweet = tweet.replace(/\\n/g, '\n');
tweet = tweet.replace(/^["'\[\]]+|["'\[\]]+$/g, '').replace(/\n{3,}/g, '\n\n').trim();

// ============================================================
// GET ORIGINAL TWEET FROM PARSE NODE (not raw Agent output)
// ============================================================
const genOutput = $('Parse AI Generate Tweet')?.first()?.json?.output;

// ALWAYS use original tweet when action is 'pass'
// Self-Critique often reformats incorrectly (removes 'i', collapses line breaks)
if (action === 'pass' && genOutput?.tweet) {
  tweet = genOutput.tweet;
} else if (!tweet && genOutput?.tweet) {
  tweet = genOutput.tweet;
}

// Get hook type from parsed generate output
let hookType = 'value';
let ammoUsed = '';
if (genOutput && typeof genOutput === 'object') {
  hookType = genOutput.type || 'value';
  ammoUsed = genOutput.ammo_used || '';
}

// CTA detection
const hasSynta = /synta/i.test(tweet);
const hasCTA = /synta\.io|\bdm\b|\breply\b|\bcomment\b/i.test(tweet);

// SMART FATIGUE HANDLING
const killPatterns = prefetch.kill_patterns || [];
let hasKillPattern = false;
let hasFatigueWarning = false;

for (const violation of fatigueViolations) {
  const lowerViolation = violation.toLowerCase();
  if (killPatterns.some(kp => lowerViolation.includes(String(kp).toLowerCase()))) {
    hasKillPattern = true;
    break;
  } else {
    hasFatigueWarning = true;
  }
}

// WEEKLY KILL PATTERNS - from weeklyAnalysis
const weeklyKillPatterns = prefetch.weekly_kill || [];
if (!hasKillPattern) {
  for (const violation of fatigueViolations) {
    const lowerViolation = violation.toLowerCase();
    if (weeklyKillPatterns.some(kp => lowerViolation.includes(String(kp).toLowerCase()))) {
      hasKillPattern = true;
      break;
    }
  }
}

// ANTI-SLOP CHECK - treat anti_slop_alerts as kill patterns
const antiSlopAlerts = prefetch.weekly_anti_slop_alerts || '';
if (!hasKillPattern && antiSlopAlerts) {
  const slopPatterns = antiSlopAlerts.toLowerCase().split('\\n')
    .filter(line => line.includes('stop:') || line.includes('urgent:'))
    .map(line => line.replace(/^(stop|urgent):\\s*/i, '').trim())
    .filter(p => p.length > 3);
  const tweetLower = tweet.toLowerCase();
  for (const pattern of slopPatterns) {
    if (tweetLower.includes(pattern)) {
      hasKillPattern = true;
      fatigueViolations.push('Anti-slop alert: ' + pattern);
      break;
    }
  }
}

let adjustedScore = avgScore;
if (hasFatigueWarning && !hasKillPattern) {
  adjustedScore = Math.max(1, avgScore - 2);
}

let shouldPass = false;
let adjustedAction = action;

if (hasKillPattern) {
  adjustedAction = 'reject';
  shouldPass = false;
} else if (avgScore >= 8 && tweet.length > 10) {
  shouldPass = true;
  adjustedAction = 'pass';
  adjustedScore = avgScore;
} else if (adjustedScore < 6) {
  adjustedAction = 'reject';
  shouldPass = false;
} else if (adjustedScore < 7) {
  adjustedAction = action === 'reject' ? 'reject' : 'rewrite';
  shouldPass = false;
} else if (tweet.length > 10) {
  shouldPass = true;
  adjustedAction = 'pass';
}

let rejectionReason = null;
if (!shouldPass) {
  if (hasKillPattern) {
    rejectionReason = 'KILL pattern: ' + fatigueViolations.join(', ');
  } else if (adjustedScore < 7 && hasFatigueWarning) {
    rejectionReason = 'Fatigue warning (-2 penalty): ' + fatigueViolations.join(', ') + ' | adjusted: ' + adjustedScore;
  } else if (adjustedScore < 7) {
    rejectionReason = 'Score ' + adjustedScore + '/10 below threshold';
  } else if (!tweet || tweet.length < 10) {
    rejectionReason = 'No valid tweet content';
  }
}

// ============================================================
// PDF BRIEF PASSTHROUGH - Pull from parsed output
// ============================================================
let pdfBrief = null;
if (genOutput && genOutput.pdf_brief && typeof genOutput.pdf_brief === 'object') {
  pdfBrief = genOutput.pdf_brief;
}

return {
  json: {
    tweet_content: tweet,
    hook_type: hookType,
    ammo_used: ammoUsed,
    scores: scores,
    original_score: avgScore,
    adjusted_score: adjustedScore,
    average_score: adjustedScore,
    fatigue_violations: fatigueViolations,
    has_kill_pattern: hasKillPattern,
    has_fatigue_warning: hasFatigueWarning,
    issues: issues,
    original_action: action,
    action: adjustedAction,
    should_pass: shouldPass,
    rejection_reason: rejectionReason,
    has_cta: hasCTA,
    cta_type: hasCTA ? (hasSynta ? 'synta' : 'engagement') : 'none',
    synta_mentioned: hasSynta,
    pdf_brief: pdfBrief,
    format: genOutput?.format || 'unknown',
    is_thread: genOutput?.is_thread || false,
    posts: genOutput?.posts || [tweet],
    post_count: genOutput?.post_count || 1,
    attempt_number: prefetch.attempt_number || 1,
    max_attempts: prefetch.max_attempts || 3,
    time_slot: prefetch.time || 'unknown',
    generation_mode: prefetch.mode || 'exploit',
    synta_required: prefetch.synta_required || false,
    status: 'processing',
    created_at: new Date().toISOString()
  }
};

