const FORMAT_CONFIG = {
  short_punchy:  { weight: 15, posts: 1, spec: 'Max 280 chars, 2-3 lines, pure impact, no line breaks' },
  medium_story:  { weight: 20, posts: 1, spec: '5-8 lines, personal story arc (setup > tension > lesson)' },
  long_insight:  { weight: 10, posts: 1, spec: '10-15 lines, framework or deep analysis, structured with natural breaks' },
  question:      { weight: 10, posts: 1, spec: '1-3 lines ending with a genuine question that sparks debate' },
  list:          { weight: 10, posts: 1, spec: 'Hook line + 3-5 items (use numbers or dashes, NOT arrows)' },
  hot_take:      { weight: 10, posts: 1, spec: 'Strong controversial opinion, 2-4 lines, must take a clear side' },
  before_after:  { weight: 5,  posts: 1, spec: 'Show transformation/contrast, use before/after framing' },
  bold_claim:    { weight: 5,  posts: 1, spec: 'Prediction or claim with specific number, 2-4 lines' },
  thread:        { weight: 20, posts: 0, spec: '' }
};
const FORMAT_TYPES = Object.keys(FORMAT_CONFIG);
const defaultWeights = Object.fromEntries(Object.entries(FORMAT_CONFIG).map(([k, v]) => [k, v.weight]));
const weights = { ...defaultWeights };

// Adjust weights from learning data
let formatPerf = {};
try { formatPerf = JSON.parse(learningFields.formatPerformance || '{}'); } catch(e) {}
for (const [format, data] of Object.entries(formatPerf)) {
  if (weights[format] !== undefined) {
    if (data.avgScore > 70) weights[format] = Math.round(weights[format] * 1.5);
    if (data.avgScore < 40) weights[format] = Math.max(2, Math.round(weights[format] * 0.3));
  }
}

// Mode adjustments
if (context.mode === 'exploit') {
  // Boost proven formats
  for (const [fmt, data] of Object.entries(formatPerf)) {
    if (data.avgScore > 70 && weights[fmt] !== undefined) weights[fmt] = Math.round(weights[fmt] * 1.5);
  }
} else if (context.mode === 'experiment' || context.mode === 'wildcard') {
  // Boost underexplored formats
  for (const fmt of FORMAT_TYPES) {
    if (!formatPerf[fmt] || (formatPerf[fmt] && formatPerf[fmt].posts < 3)) {
      weights[fmt] = Math.round((weights[fmt] || 10) * 1.8);
    }
  }
}

// CTA slot adjustments
if (context.has_cta) {
  weights.medium_story = Math.round(weights.medium_story * 1.8);
  weights.thread = Math.round(weights.thread * 1.8);
  weights.short_punchy = Math.round(weights.short_punchy * 0.4);
}

// Weighted random selection
const totalWeight = Object.values(weights).reduce((a, b) => a + b, 0);
let random = Math.random() * totalWeight;
let selectedFormat = 'medium_story';
for (const [format, weight] of Object.entries(weights)) {
  random -= weight;
  if (random <= 0) { selectedFormat = format; break; }
}
context.target_format = selectedFormat;

// Thread post count selection (weighted: shorter threads more likely)
const THREAD_POST_WEIGHTS = { 2: 40, 3: 25, 4: 15, 5: 10, 6: 5, 7: 5 };
let threadPostCount = 1;
if (context.target_format === 'thread') {
  const tEntries = Object.entries(THREAD_POST_WEIGHTS);
  const tTotal = tEntries.reduce((s, [_, w]) => s + w, 0);
  let tRand = Math.random() * tTotal;
  for (const [count, w] of tEntries) {
    tRand -= w;
    if (tRand <= 0) { threadPostCount = parseInt(count); break; }
  }
}

// Dynamic thread spec generator
function getThreadSpec(n) {
  const roles = ['hook', 'context/setup', 'evidence/proof', 'insight/analysis', 'deeper point'];
  const labels = [];
  for (let i = 0; i < n; i++) {
    if (i === 0) labels.push('Post 1: hook/scroll-stopper');
    else if (i === n - 1) labels.push('Post ' + (i+1) + ': conclusion/CTA');
    else labels.push('Post ' + (i+1) + ': ' + roles[Math.min(i, roles.length-1)]);
  }
  return n + ' posts separated by ---THREAD_BREAK---. ' + labels.join('. ') + '. Each post under 280 chars';
}

