// Parse AI Generate Tweet output - preserves line breaks
const raw = $input.first().json.output;

// Catch empty/null responses from LLM
if (!raw || (typeof raw === 'string' && raw.trim() === '')) {
  throw new Error('LLM returned empty response - retry needed');
}

let parsed;
if (typeof raw === 'string') {
  const cleaned = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  parsed = JSON.parse(cleaned);
} else if (typeof raw === 'object' && raw !== null) {
  parsed = raw;
} else {
  throw new Error('No valid output from AI Generate Tweet');
}

let tweet = parsed.tweet || '';
const type = parsed.type || 'value';
const ammoUsed = parsed.ammo_used || '';
const pdfBrief = parsed.pdf_brief || null;

// Normalize line breaks - handle literal \\n that didn't get parsed
tweet = tweet.replace(/\\n/g, '\n');
// Clean up excessive line breaks (3+ → 2)
tweet = tweet.replace(/\n{3,}/g, '\n\n');
tweet = tweet.trim();

if (!tweet || tweet.length < 10) {
  throw new Error('LLM returned empty or too-short tweet');
}

// Format extraction
const format = parsed.format || 'unknown';
const isThread = format.startsWith('thread_');
let posts = [];
if (isThread && tweet.includes('---THREAD_BREAK---')) {
  posts = tweet.split('---THREAD_BREAK---').map(p => p.trim()).filter(p => p.length > 0);
} else {
  posts = [tweet];
}

const hasSynta = /synta/i.test(tweet);
const hasCTA = /synta\(?\.\)?io|\bdm\b|\breply\b|\bcomment\b/i.test(tweet);

const output = {
  tweet,
  type,
  format: format,
  is_thread: isThread,
  posts: posts,
  post_count: posts.length,
  ammo_used: ammoUsed,
  pdf_brief: pdfBrief,
  has_synta: hasSynta,
  has_cta: hasCTA,
  cta_type: hasCTA ? (hasSynta ? 'synta' : 'engagement') : 'none'
};

if (pdfBrief && typeof pdfBrief === 'object') {
  output.pdf_brief = {
    title: pdfBrief.title || '',
    subtitle: pdfBrief.subtitle || '',
    sections: Array.isArray(pdfBrief.sections) ? pdfBrief.sections : [],
    key_deliverables: Array.isArray(pdfBrief.key_deliverables) ? pdfBrief.key_deliverables : [],
    target_word_count: pdfBrief.target_word_count || 1500,
    tone: pdfBrief.tone || 'educational'
  };
}

return { json: { output } };

// PREPARE FOR AIRTABLE v1.0 - Maps Process Critique output to Airtable schema
const input = $input.first().json;

return {
